-- Enable RLS on every table that holds tenant data
ALTER TABLE users          ENABLE ROW LEVEL SECURITY;
ALTER TABLE conversations  ENABLE ROW LEVEL SECURITY;
ALTER TABLE messages       ENABLE ROW LEVEL SECURITY;

-- Create policies: a row is visible only if its tenant_id matches
-- the session variable set by the application on connection
CREATE POLICY tenant_isolation ON users
    USING (tenant_id = current_setting('app.current_tenant')::uuid);

CREATE POLICY tenant_isolation ON conversations
    USING (tenant_id = current_setting('app.current_tenant')::uuid);

CREATE POLICY tenant_isolation ON messages
    USING (tenant_id = current_setting('app.current_tenant')::uuid);

-- The application sets the session variable after authenticating:
-- SET LOCAL app.current_tenant = '<tenant-uuid>';
-- Use SET LOCAL (not SET) so it resets at transaction end.

CREATE ROLE app_user NOLOGIN;
GRANT SELECT, INSERT, UPDATE, DELETE ON users, conversations, messages TO app_user;
-- Superusers bypass RLS by default — never use them for application queries

-- Users: look up by tenant (RLS will use this + table scan for tenant sets)
CREATE INDEX ON users (tenant_id);

-- Conversations: list a user's recent active conversations
CREATE INDEX ON conversations (user_id, updated_at DESC)
    WHERE deleted_at IS NULL;   -- partial: exclude soft-deleted

-- Conversations: admin view — all conversations for a tenant
CREATE INDEX ON conversations (tenant_id, updated_at DESC);

-- Messages: load a conversation's full history in order
CREATE INDEX ON messages (conversation_id, created_at);

-- Messages: sum tokens per tenant for billing
CREATE INDEX ON messages (tenant_id, created_at DESC);

-- Messages: full-text search across conversation content
CREATE INDEX ON messages USING GIN (
    to_tsvector('english', content ->> 'text')
) WHERE role = 'user';  -- search user messages only

-- Messages: JSONB path queries (e.g. find tool-use messages)
CREATE INDEX ON messages USING GIN (content);
